import java.io.*;
import java.util.*;

public class Main {
    private static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do {
                c = readByte();
                if (c == -1) return Integer.MIN_VALUE; // end of stream
            } while (c <= ' ');
            if (c == '-' ) { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();
        int T = fs.nextInt();
        for (int t = 0; t < T; t++) {
            int N = fs.nextInt();
            int M = fs.nextInt();
            int[] a = new int[N];
            for (int i = 0; i < N; i++) a[i] = fs.nextInt();
            Arrays.sort(a);
            int[] bins = new int[N]; // remaining capacity of each bin
            int binCnt = 0;
            for (int i = N - 1; i >= 0; i--) {
                int sz = a[i];
                boolean placed = false;
                for (int j = 0; j < binCnt; j++) {
                    if (bins[j] >= sz) {
                        bins[j] -= sz;
                        placed = true;
                        break;
                    }
                }
                if (!placed) {
                    bins[binCnt++] = M - sz;
                }
            }
            out.append(binCnt);
            if (t != T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

